package com.seaquake6324.civitas.application;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.population.FamilyMemberRef;import java.util.*;import org.junit.jupiter.api.Test;
class PlanNpcMarriagesServiceTest{
 @Test void pairsOnlyEligibleSameCityCandidatesInStableLinearOrder(){UUID city=UUID.randomUUID(),other=UUID.randomUUID();var a=candidate(1,city,true,true,false,false,80);var child=candidate(2,city,true,false,false,false,90);var low=candidate(3,city,true,true,false,false,20);var b=candidate(4,city,true,true,false,false,75);var c=candidate(5,other,true,true,false,false,80);var d=candidate(6,other,true,true,false,false,80);var result=new PlanNpcMarriagesService().plan(List.of(a,child,low,b,c,d),60,4);assertEquals(List.of(new PlanNpcMarriagesService.Pair(a,b),new PlanNpcMarriagesService.Pair(c,d)),result.pairs());assertEquals(6,result.examined());assertEquals(4,result.eligible());assertFalse(result.truncated());}
 @Test void pairCapStopsWorkExactlyAndReportsTruncation(){UUID city=UUID.randomUUID();List<PlanNpcMarriagesService.Candidate>values=List.of(candidate(1,city,true,true,false,false,80),candidate(2,city,true,true,false,false,80),candidate(3,city,true,true,false,false,80),candidate(4,city,true,true,false,false,80));var result=new PlanNpcMarriagesService().plan(values,60,1);assertEquals(1,result.pairs().size());assertEquals(2,result.examined());assertTrue(result.truncated());}
 @Test void refusesPlayerCandidates(){assertThrows(IllegalArgumentException.class,()->new PlanNpcMarriagesService.Candidate(FamilyMemberRef.player(UUID.randomUUID()),UUID.randomUUID(),true,true,false,false,80,1));}
 private static PlanNpcMarriagesService.Candidate candidate(long id,UUID city,boolean alive,boolean adult,boolean partnered,boolean active,double willingness){return new PlanNpcMarriagesService.Candidate(FamilyMemberRef.citizen(new UUID(0,id)),city,alive,adult,partnered,active,willingness,1);}
}
